 15→/**
 16→ * Training session API routes.
 17→ * POST /api/training/{tenant}/session — start a new training session (T013)
 18→ *                                      or start remediation for a failed session (T022)
 19→ * GET  /api/training/{tenant}/session — get current session state (T014)
 20→ */
 21→
 22→import { getSnapshot } from "@/config/index";
 23→import { resolveModel } from "@/intake/ai-model-resolver";
 24→import { ProfileRepository } from "@/intake/profile-repository";
 25→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 26→import { logRemediationInitiated, logSessionStarted } from "@/training/audit";
 27→import { CurriculumGenerationError, generateCurriculum } from "@/training/curriculum-generator";
 28→import {
 29→  RemediationPlanError,
 30→  generateRemediationCurriculum,
 31→} from "@/training/remediation-planner";
 32→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 33→import { transitionSession } from "@/training/state-machine";
 34→import type { TrainingModule } from "@/training/types";
 35→import { NextResponse } from "next/server";
 36→
 37→// ---------------------------------------------------------------------------
 38→// Shared storage / repos (module-level singletons, as per existing patterns)
 39→// ---------------------------------------------------------------------------
 40→
 41→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 42→const profileRepo = new ProfileRepository(storage);
 43→const sessionRepo = new SessionRepository(storage);
 44→
 45→// ---------------------------------------------------------------------------
 46→// Helper — strip server-only fields from module content before sending
 47→// ---------------------------------------------------------------------------
 48→
 49→function stripServerFields(module: TrainingModule): unknown {
 50→  if (!module.content) return module;
 51→  return {
 52→    ...module,
 53→    content: {
 54→      ...module.content,
 55→      scenarios: module.content.scenarios.map(({ rubric: _rubric, ...s }) => ({
 56→        ...s,
 57→        options: s.options?.map(({ correct: _correct, ...o }) => o),
 58→      })),
 59→      quiz: module.content.quiz
 60→        ? {
 61→            questions: module.content.quiz.questions.map(({ rubric: _rubric, ...q }) => ({
 62→              ...q,
 63→              options: q.options?.map(({ correct: _correct, ...o }) => o),
 64→            })),
 65→          }
 66→        : module.content.quiz,
 67→    },
 68→  };
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// POST — T013: Start a new training session; T022: Remediation
 73→// ---------------------------------------------------------------------------
 74→
 75→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 76→  const { tenant: tenantSlug } = await params;
 77→  const tenantId = request.headers.get("x-tenant-id");
 78→  const employeeId = request.headers.get("x-employee-id");
 79→
 80→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 81→    return NextResponse.json(
 82→      { error: "unauthorized", message: "Not authenticated" },
 83→      { status: 401 },
 84→    );
 85→  }
 86→
 87→  await storage.initialize();
 88→
 89→  // 1. Check for existing active session — 409 if one exists
 90→  const existingSession = await sessionRepo.findActiveSession(tenantId, employeeId);
 91→  if (existingSession) {
 92→    return NextResponse.json(
 93→      { error: "conflict", message: "An active training session already exists" },
 94→      { status: 409 },
 95→    );
 96→  }
 97→
 98→  // Resolve tenant config (needed for both fresh and remediation paths)
 99→  const snapshot = getSnapshot();
100→  const tenant = snapshot?.tenants.get(tenantSlug);
101→  if (!tenant) {
102→    return NextResponse.json({ error: "not_found", message: "Tenant not found" }, { status: 404 });
103→  }
104→  const model = resolveModel(tenant);
105→  const maxModules = tenant.settings.training?.maxModules ?? 8;
106→  const maxAttempts = tenant.settings.training?.maxAttempts ?? 3;
107→  const enableRemediation = tenant.settings.training?.enableRemediation ?? true;
108→
109→  // 2. T022: Check for a failed session with attempts remaining — start remediation
110→  const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 10 });
111→  const failedSession =
112→    history.find((s) => s.status === "failed" && s.attemptNumber < maxAttempts) ?? null;
113→
114→  if (failedSession) {
115→    // 2a. Remediation must be enabled
116→    if (!enableRemediation) {
117→      return NextResponse.json(
118→        { error: "conflict", message: "Remediation is not enabled for this tenant" },
119→        { status: 409 },
120→      );
121→    }
122→
123→    // 2b. Find confirmed role profile — 404 if none
124→    const profile = await profileRepo.findByEmployee(tenantId, employeeId);
125→    if (!profile) {
126→      return NextResponse.json(
127→        { error: "not_found", message: "No confirmed role profile found" },
128→        { status: 404 },
129→      );
130→    }
131→
132→    // 2c. Generate remediation curriculum focused on weak areas
133→    const weakAreas = failedSession.weakAreas ?? [];
134→    let remediationCurriculum: Awaited<ReturnType<typeof generateRemediationCurriculum>>;
135→    try {
136→      remediationCurriculum = await generateRemediationCurriculum(
137→        weakAreas,
138→        profile,
139→        { maxModules },
140→        model,
141→      );
142→    } catch (error) {
143→      if (error instanceof RemediationPlanError) {
144→        if (error.code === "ai_unavailable") {
145→          return NextResponse.json(
146→            { error: "ai_unavailable", message: "AI service temporarily unavailable" },
147→            { status: 503 },
148→          );
149→        }
150→        return NextResponse.json(
151→          { error: "planning_failed", message: error.message },
152→          { status: 422 },
153→        );
154→      }
155→      return NextResponse.json(
156→        { error: "internal_error", message: "An unexpected error occurred" },
157→        { status: 500 },
158→      );
159→    }
160→
161→    // 2d. Increment attemptNumber and transition the failed session through remediation states
162→    const newAttemptNumber = failedSession.attemptNumber + 1;
163→
164→    // Transition: failed → in-remediation
165→    transitionSession(failedSession.status, "remediation-started");
166→    // Transition: in-remediation → in-progress
167→    transitionSession("in-remediation", "remediation-modules-ready");
168→
169→    // 2e. Update the existing session with new curriculum, status, and attemptNumber
170→    let updatedSession: Awaited<ReturnType<typeof sessionRepo.updateSession>>;
171→    try {
172→      updatedSession = await sessionRepo.updateSession(
173→        tenantId,
174→        failedSession.id,
175→        {
176→          status: "in-progress",
177→          attemptNumber: newAttemptNumber,
178→          curriculum: remediationCurriculum,
179→          weakAreas: null,
180→          aggregateScore: null,
181→          completedAt: null,
182→        },
183→        failedSession.version,
184→      );
185→    } catch (err) {
186→      if (err instanceof VersionConflictError) {
187→        return NextResponse.json(
188→          { error: "conflict", message: "Session was modified by another request" },
189→          { status: 409 },
190→        );
191→      }
192→      throw err;
193→    }
194→
195→    // 2f. Create new module records for the remediation curriculum
196→    const now = new Date().toISOString();
197→    const remediationModuleData = remediationCurriculum.modules.map((m, i) => ({
198→      tenantId,
199→      sessionId: failedSession.id,
200→      moduleIndex: i,
201→      title: m.title,
202→      topicArea: m.topicArea,
203→      jobExpectationIndices: m.jobExpectationIndices,
204→      status: "locked" as const,
205→      content: null,
206→      scenarioResponses: [],
207→      quizAnswers: [],
208→      moduleScore: null,
209→      version: 1,
210→      createdAt: now,
211→      updatedAt: now,
212→    }));
213→
214→    const remediationModules = await sessionRepo.createModules(tenantId, remediationModuleData);
215→
216→    // 2g. Log remediation audit event
217→    await logRemediationInitiated(
218→      storage,
219→      tenantId,
220→      employeeId,
221→      failedSession.id,
222→      newAttemptNumber,
223→      weakAreas.length,
224→      weakAreas,
225→    );
226→
227→    // 2h. Return 201 with updated session + new modules
228→    return NextResponse.json(
229→      { session: updatedSession, modules: remediationModules.map(stripServerFields) },
230→      { status: 201 },
231→    );
232→  }
233→
234→  // 3. No active session and no failed session with attempts remaining — fresh session
235→  // Find confirmed role profile — 404 if none
236→  const profile = await profileRepo.findByEmployee(tenantId, employeeId);
237→  if (!profile) {
238→    return NextResponse.json(
239→      { error: "not_found", message: "No confirmed role profile found" },
240→      { status: 404 },
241→    );
242→  }
243→
244→  // 4. Generate curriculum via AI
245→  let curriculum: Awaited<ReturnType<typeof generateCurriculum>>;
246→  try {
247→    curriculum = await generateCurriculum(profile, { maxModules }, model);
248→  } catch (error) {
249→    if (error instanceof CurriculumGenerationError) {
250→      if (error.code === "ai_unavailable") {
251→        return NextResponse.json(
252→          { error: "ai_unavailable", message: "AI service temporarily unavailable" },
253→          { status: 503 },
254→        );
255→      }
256→      return NextResponse.json(
257→        { error: "generation_failed", message: error.message },
258→        { status: 422 },
259→      );
260→    }
261→    return NextResponse.json(
262→      { error: "internal_error", message: "An unexpected error occurred" },
263→      { status: 500 },
264→    );
265→  }
266→
267→  // 5. Create session record
268→  const now = new Date().toISOString();
269→  const session = await sessionRepo.createSession(tenantId, {
270→    tenantId,
271→    employeeId,
272→    roleProfileId: profile.id,
273→    roleProfileVersion: profile.version,
274→    configHash: snapshot?.configHash ?? "unknown",
275→    appVersion: process.env.APP_VERSION ?? "unknown",
276→    status: "in-progress",
277→    attemptNumber: 1,
278→    curriculum,
279→    aggregateScore: null,
280→    weakAreas: null,
281→    version: 1,
282→    createdAt: now,
283→    updatedAt: now,
284→    completedAt: null,
285→  });
286→
287→  // 6. Create module records for each curriculum module
288→  const moduleData = curriculum.modules.map((m, i) => ({
289→    tenantId,
290→    sessionId: session.id,
291→    moduleIndex: i,
292→    title: m.title,
293→    topicArea: m.topicArea,
294→    jobExpectationIndices: m.jobExpectationIndices,
295→    status: "locked" as const,
296→    content: null,
297→    scenarioResponses: [],
298→    quizAnswers: [],
299→    moduleScore: null,
300→    version: 1,
301→    createdAt: now,
302→    updatedAt: now,
303→  }));
304→
305→  const modules = await sessionRepo.createModules(tenantId, moduleData);
306→
307→  // 7. Log audit event
308→  await logSessionStarted(
309→    storage,
310→    tenantId,
311→    employeeId,
312→    session.id,
313→    1,
314→    profile.version,
315→    snapshot?.configHash ?? "unknown",
316→  );
317→
318→  // 8. Return 201 with session + modules
319→  return NextResponse.json({ session, modules: modules.map(stripServerFields) }, { status: 201 });
320→}
321→
322→// ---------------------------------------------------------------------------
323→// GET — T014: Get current session state
324→// ---------------------------------------------------------------------------
325→
326→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
327→  const { tenant: tenantSlug } = await params;
328→  const tenantId = request.headers.get("x-tenant-id");
329→  const employeeId = request.headers.get("x-employee-id");
330→
331→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
332→    return NextResponse.json(
333→      { error: "unauthorized", message: "Not authenticated" },
334→      { status: 401 },
335→    );
336→  }
337→
338→  await storage.initialize();
339→
340→  // Parse query parameters
341→  const url = new URL(request.url);
342→  const isHistory = url.searchParams.get("history") === "true";
343→
344→  // T030: History mode — return all sessions with their modules
345→  if (isHistory) {
346→    const sessions = await sessionRepo.findSessionHistory(tenantId, employeeId);
347→    const sessionsWithModules = await Promise.all(
348→      sessions.map(async (sess) => {
349→        const modules = await sessionRepo.findModulesBySession(tenantId, sess.id);
350→        const clientModules = modules.map(stripServerFields);
351→        return { session: sess, modules: clientModules };
352→      }),
353→    );
354→    return NextResponse.json(sessionsWithModules);
355→  }
356→
357→  // T014: Default mode — return active or most recent session
358→  let session = await sessionRepo.findActiveSession(tenantId, employeeId);
359→  if (!session) {
360→    const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 1 });
361→    session = history[0] ?? null;
362→  }
363→
364→  if (!session) {
365→    return NextResponse.json(
366→      { error: "not_found", message: "No training session found" },
367→      { status: 404 },
368→    );
369→  }
370→
371→  // 2. Find modules for this session
372→  const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
373→
374→  // 3. Strip server-only fields (correct answers, rubrics) from module content
375→  const clientModules = modules.map(stripServerFields);
376→
377→  return NextResponse.json({ session, modules: clientModules });
378→}
